// C++ Solution
#include <bits/stdc++.h>

using namespace std;

class Solution {
public:
    bool topologicalSort(vector<vector<char>>& graph) {
        unordered_set<int> visited;
        stack<int> stack;

        for (auto& node : graph) {
            dfs(node, visited, stack);
        }

        // Check if all nodes are visited
        return visited.size() == graph.size();
    }

    void dfs(vector<char>& node, unordered_set<int>& visited, stack<int>& stack) {
        visited.insert(node[0]);

        for (auto neighbor : graph[node[0]]) {
            if (neighbor[0] not in visited) {
                dfs(neighbor, visited, stack);
            }
        }

        stack.push(node[0]);
    }
};
